#[tokio::test]
async fn test_batch_invoke_parallel_execution() {
    // Independent ops run in parallel
    let harness = TestHarness::new().await;
    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "test.echo".into(), input: json!({"delay_ms": 100}), depends_on: vec![] },
            BatchOperation { id: "op2".into(), tool: "test.echo".into(), input: json!({"delay_ms": 100}), depends_on: vec![] },
        ],
        options: BatchOptions { max_parallelism: 5, stop_on_first_error: false, timeout: Duration::from_secs(30) },
    };

    let start = Instant::now();
    let response = harness.batch_invoke(batch).await.unwrap();
    let elapsed = start.elapsed();

    // Should complete in ~100ms, not 200ms (parallel)
    assert!(elapsed.as_millis() < 150);
    assert_eq!(response.completed, 2);
}

#[tokio::test]
async fn test_batch_invoke_dependency_ordering() {
    // op2 depends on op1, must run after
    let harness = TestHarness::new().await;
    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "test.set_state".into(), input: json!({"key": "x", "value": 1}), depends_on: vec![] },
            BatchOperation { id: "op2".into(), tool: "test.get_state".into(), input: json!({"key": "x"}), depends_on: vec!["op1".into()] },
        ],
        options: BatchOptions::default(),
    };

    let response = harness.batch_invoke(batch).await.unwrap();
    assert_eq!(response.results[1].output["value"], 1);
}

#[tokio::test]
async fn test_batch_invoke_partial_failure() {
    // Second op fails, first succeeds
    let harness = TestHarness::new().await;
    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "test.echo".into(), input: json!({}), depends_on: vec![] },
            BatchOperation { id: "op2".into(), tool: "test.fail".into(), input: json!({}), depends_on: vec![] },
        ],
        options: BatchOptions { stop_on_first_error: false, ..Default::default() },
    };

    let response = harness.batch_invoke(batch).await.unwrap();
    assert_eq!(response.status, "partial_success");
    assert_eq!(response.completed, 1);
    assert_eq!(response.failed, 1);
}

